#include <cstddef>
#include <cstdint>
#include <omp.h>

/* 
 * Triangular solve for a lower‑triangular matrix L.
 * L is supplied in a flat row‑major array of size n * n.
 *  x = L^{-1} * b
 *
 * The function is thread‑safe but serial in the inner loop because
 * each row depends on all previously computed rows.  We simply
 * parallelise the outer loop over the rows that are independent
 * (the “sqrt‑block” approach) or leave it serial for simplicity.
 * Since the input size is small enough that the total work is
 * dominated by the sequential dependency, the best strategy is
 * to keep the algorithm as close as possible to the original
 * while using cached, contiguous data.
 */

extern "C" void kernel_trisolv(int n,
                               const double * restrict L,
                               double * restrict x,
                               const double * restrict b)
{
    // Main loop - as close as possible to the original
    for (int i = 0; i < n; ++i) {
        double sum = b[i];
        const double * Li  = L + i * n;                // row i of L
        double *  xi       = &x[i];

        // subtract contributions from already computed x[j]
        for (int j = 0; j < i; ++j) {
            sum -= Li[j] * x[j];
        }
        *xi = sum / Li[i];
    }
}
