#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
		      int n,
		      std::vector<double>& A,
		      std::vector<double>& B)
{
    const double coeff = 0.33333;
    double *restrict a = A.data();
    double *restrict b = B.data();

    /* The outer time‑step loop cannot be parallelised due to
       data dependencies between consecutive steps.  The inner
       spatial loops, however, are completely independent and can
       safely be parallelised. */
    for (int t = 0; t < tsteps; ++t) {
        /* First half‑step: update B from A */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            b[i] = coeff * (a[i - 1] + a[i] + a[i + 1]);
        }

        /* Second half‑step: update A from B */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            a[i] = coeff * (b[i - 1] + b[i] + b[i + 1]);
        }
    }
}
