/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y)
{
    /* Ensure the temporary vector has the correct size; this
       does not change the original behaviour but protects
       against accidental out‑of‑bounds writes if the caller
       resized the vector during the call. */
    if (static_cast<int>(tmp.size()) != n)
        tmp.resize(n);

    /* Parallel over rows.  Each iteration is independent
       so a simple static schedule is adequate. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double t  = 0.0;
        double yv = 0.0;
        const double* arow = A[i].data();
        const double* brow = B[i].data();
        for (int j = 0; j < n; ++j) {
            t  += arow[j] * x[j];
            yv += brow[j] * x[j];
        }
        tmp[i] = t;
        y[i]   = alpha * t + beta * yv;
    }
}
