void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // outer loop on k kept serial to preserve the algorithmic dependence
    for (int k = 0; k < n; ++k) {
        const std::vector<int>& row_k = path[k];           // read‑only reference to k‑th row
        // parallelise the i‑loop; each thread works on a distinct row
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < n; ++i) {
            std::vector<int>& row_i = path[i];           // writable reference to i‑th row
            // local pointer to the k‑th element of row i for speed
            const int* pk = &row_i[k];
            const int* pk_col = &row_k[0];              // pointer to the whole k‑th row
            for (int j = 0; j < n; ++j) {
                int new_val = (*pk) + pk_col[j];
                if (new_val < row_i[j]) {
                    row_i[j] = new_val;
                }
            }
        }
    }
}
