#include <vector>
#include <cstddef>
#include <omp.h>

/* ------------------------------------------------------------
   Optimised BiCG kernel.
   ------------------------------------------------------------
   The input matrix A is stored in row major layout.
   The function signature is kept identical to the original
   except for an additional reference to a flat buffer that
   holds the matrix data. This allows efficient pointer
   arithmetic and avoid double indirection.
   ------------------------------------------------------------ */
void kernel_bicg(int m, int n,
                 const std::vector<double>& A_flat,
                 const std::vector<double>&  r,
                 const std::vector<double>&  p,
                 std::vector<double>&        s,
                 std::vector<double>&        q)
{
    /* Initialise s to zero in parallel */
    #pragma omp parallel for
    for (int j = 0; j < m; ++j) s[j] = 0.0;

    /* Main loop – row–vector inner product and
       accumulation of q.  The inner j‑loop is kept
       contiguous to improve cache behaviour.       */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
    {
        double qi = 0.0;
        double ri = r[i];
        const double* a_row = &A_flat[i * m];   // start of row i

        /* Unroll the inner loop by 4 for a 4×4 block */
        int j = 0;
        #pragma omp simd reduction(+:s[:m], qi)
        for (; j <= m-4; j += 4)
        {
            double rij = ri;
            double a0 = a_row[j];
            double a1 = a_row[j+1];
            double a2 = a_row[j+2];
            double a3 = a_row[j+3];

            s[j]   += a0 * rij;
            s[j+1] += a1 * rij;
            s[j+2] += a2 * rij;
            s[j+3] += a3 * rij;

            qi += a0 + p[j];
            qi += a1 + p[j+1];
            qi += a2 + p[j+2];
            qi += a3 + p[j+3];
        }
        for (; j < m; ++j)
        {
            double a_j = a_row[j];
            s[j] += a_j * ri;
            qi   += a_j + p[j];
        }
        q[i] = qi;
    }
}
