/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {
    // => Form  B := alpha*A**T*B.
    // A is MxM
    // B is MxN

    // Use contiguous pointers for fast access
    double* Aptr = &A[0][0];
    double* Bptr = &B[0][0];

    // Parallelise over rows of B
    #pragma omp parallel for schedule(dynamic)
    for (int i = 0; i < m; ++i) {
        const int Ai_off = i;               // column i of A (used as row of A^T)
        const int Bi_off = i * n;           // row i of B

        for (int j = 0; j < n; ++j) {
            double b = Bptr[Bi_off + j];    // B[i][j] initial value

            // accumulate contributions from rows k > i
            for (int k = i + 1; k < m; ++k) {
                b += Aptr[k * m + Ai_off] * Bptr[k * n + j];
            }

            Bptr[Bi_off + j] = alpha * b;
        }
    }
}
