void kernel_doitgen(int nr, int nq, int np,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<double>>& C4,
                    std::vector<double>& sum) {
    // Avoid frequent bounds checks by taking raw pointers
    const std::size_t np_sz = static_cast<std::size_t>(np);
    const std::size_t nq_sz = static_cast<std::size_t>(nq);
    const std::size_t nr_sz = static_cast<std::size_t>(nr);

    // Flatten C4 for faster access
    std::vector<double> flatC4(np_sz * np_sz);
    for (std::size_t s = 0; s < np_sz; ++s)
        std::copy(C4[s].begin(), C4[s].end(), flatC4.begin() + s * np_sz);

    #pragma omp parallel for collapse(2) schedule(static)
    for (int r = 0; r < nr_sz; ++r) {
        for (int q = 0; q < nq_sz; ++q) {
            double* a_row = A[r][q].data();       // pointer to A[r][q][0]
            const double* a_panel = a_row;        // reused for each p
            double* sum_row = sum.data();         // temporary buffer

            // Compute A[r][q][:] = sum_s A[r][q][s] * C4[s][:]
            for (int p = 0; p < np_sz; ++p) {
                double prod = 0.0;
                const double* c_col = flatC4.data() + p * np_sz; // C4[ ][p]

                #pragma omp simd
                for (int s = 0; s < np_sz; ++s)
                    prod += a_panel[s] * c_col[s];

                sum_row[p] = prod;
            }

            // Copy result back into A[r][q][:] (row already points there)
            std::copy(sum_row, sum_row + np_sz, a_row);
        }
    }
}
