#include <vector>
#include <cstddef>
#include <omp.h>

/*Pre‑condition: All vectors are of the correct shape and hold data
  in row‑major order, i.e. row[i] points to the first element of row i.
  The function does *not* modify the topology of the vectors – it only
  changes the values stored in them.  This guarantees that the
  benchmark harness sees exactly the same behavior as the original
  implementation while allowing us to use raw pointers for maximum
  speed.
*/
void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B)
{
    const double a = alpha, b = beta;

    /* Convert to arrays of pointers for fast access */
    double **c = new double*[n];
    double **a_mat = new double*[m];
    double **b_mat = new double*[m];

    for (int i = 0; i < n; ++i) c[i] = C[i].data();
    for (int j = 0; j < m; ++j) a_mat[j] = A[j].data();
    for (int j = 0; j < m; ++j) b_mat[j] = B[j].data();

    /* Parallel over the outermost loop, no race condition because
       each thread writes to a distinct row of C. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double *ci = c[i];

        /* --- scale the lower triangle by beta --- */
        for (int j = 0; j <= i; ++j) {
            ci[j] *= b;
        }

        /* --- accumulate the rank‑k update --- */
        for (int k = 0; k < m; ++k) {
            const double aik = a_mat[k][i];   // A[i][k]
            const double bik = b_mat[k][i];   // B[i][k]
            const double alpha_aik = a * aik;
            const double alpha_bik = a * bik;

            double *ak_row = a_mat[k];
            double *bk_row = b_mat[k];

            for (int j = 0; j <= i; ++j) {
                ci[j] += ak_row[j] * alpha_bik + bk_row[j] * alpha_aik;
            }
        }
    }

    delete[] c;
    delete[] a_mat;
    delete[] b_mat;
}
