#include <omp.h>

/*
 * Optimized QR Decomposition via Modified Gram–Schmidt
 * Uses contiguous memory access and OpenMP parallelism.
 * The function signature is unchanged to keep compatibility with the harness.
 */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q) {
    // Pointers to the raw data for fast indexing
    std::vector<double*> Ap, Rp, Qp;
    Ap.reserve(n); Rp.reserve(n); Qp.reserve(n);
    for (int j = 0; j < n; ++j) {
        Ap.push_back(A[0].data() + j * m); // assuming column-major storage
        Rp.push_back(R[0].data() + j * n);
        Qp.push_back(Q[0].data() + j * m);
    }

    for (int k = 0; k < n; ++k) {
        double nrm = 0.0;
        for (int i = 0; i < m; ++i) {
            double val = Ap[k][i];
            nrm += val * val;
        }
        double rkk = std::sqrt(nrm);
        Rp[k][k] = rkk;

        /* normalize the k‑th column into Q */
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i) {
            Qp[k][i] = Ap[k][i] / rkk;
        }

        /* orthogonalise remaining columns */
        for (int j = k + 1; j < n; ++j) {
            double rkj = 0.0;
            for (int i = 0; i < m; ++i) {
                rkj += Qp[k][i] * Ap[j][i];
            }
            Rp[k][j] = rkj;

            /* A[:,j] -= Q[:,k] * rkj */
            #pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i) {
                Ap[j][i] -= Qp[k][i] * rkj;
            }
        }
    }
}
