/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gemver(int n,
                   double alpha,
                   double beta,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& u1,
                   std::vector<double>& v1,
                   std::vector<double>& u2,
                   std::vector<double>& v2,
                   std::vector<double>& w,
                   std::vector<double>& x,
                   std::vector<double>& y,
                   std::vector<double>& z)
{
    // Ensure each row of A is contiguous for faster access
    const std::size_t stride = n;

    /* 1. Update A[i][j] = A[i][j] + u1[i]*v1[j] + u2[i]*v2[j] */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double ui1 = u1[i];
        double ui2 = u2[i];
        double* Ai = A[i].data();          // pointer to row i
        for (int j = 0; j < n; ++j) {
            Ai[j] += ui1 * v1[j] + ui2 * v2[j];
        }
    }

    /* 2. x[i] += beta * sum_j A[j][i] * y[j]  (column‑wise accumulation) */
    // We compute column‑wise, but inner loop is over rows.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        for (int j = 0; j < n; ++j) {
            sum += A[j][i] * y[j];
        }
        x[i] += beta * sum;
    }

    /* 3. Element‑wise addition */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        x[i] += z[i];
    }

    /* 4. w[i] += alpha * sum_j A[i][j] * x[j] */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        double* Ai = A[i].data();          // pointer to row i
        for (int j = 0; j < n; ++j) {
            sum += Ai[j] * x[j];
        }
        w[i] += alpha * sum;
    }
