#include <vector>
#include <cstdint>
#include <omp.h>

// Helper for max
constexpr inline int16_t vmax16(int16_t a, int16_t b) { return a > b ? a : b; }

// Match function (A=0,C=1,G=2,U=3)
inline int16_t match16(uint8_t b1, uint8_t b2) {
    return (b1 + b2 == 3) ? 1 : 0;
}

void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table) {

    // Make data contiguous for better cache usage
    std::vector<uint8_t> seq8(seq.begin(), seq.end());            // 1 byte per base
    std::vector<int16_t> flat(n * n, 0);                          // 2‑byte per score

    int16_t* tbl = flat.data();
    const int16_t* seqPtr = seq8.data();

    const int outer_step = 64;  // tile size for outer loop
    const int inner_step = 64;  // tile size for inner loop

    for (int ii = n - 1; ii >= 0; ii -= outer_step) {
        const int i_max = std::min(ii, n - 1);
        const int i_min = ii - outer_step + 1;
#pragma omp for schedule(static)
        for (int i = i_min; i <= i_max; ++i) {
            for (int j = i + 1; j < n; ++j) {
                int16_t best = tbl[i * n + j];

                // Predecessor tables
                if (j - 1 >= 0)
                    best = vmax16(best, tbl[i * n + (j - 1)]);
                if (i + 1 < n)
                    best = vmax16(best, tbl[(i + 1) * n + j]);

                // Closing pair
                if (j - 1 >= 0 && i + 1 < n) {
                    int16_t cand;
                    if (i < j - 1)
                        cand = tbl[(i + 1) * n + (j - 1)] + match16(seqPtr[i], seqPtr[j]);
                    else
                        cand = tbl[(i + 1) * n + (j - 1)];
                    best = vmax16(best, cand);
                }

                // Bifurcation
                for (int k = i + 1; k < j; ++k)
                    best = vmax16(best, tbl[i * n + k] + tbl[(k + 1) * n + j]);

                tbl[i * n + j] = best;
            }
        }
    }

    // Copy back to the 2‑D vector provided by the harness
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            table[i][j] = flat[i * n + j];
}
