#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    // Provide contiguous access to the inner vectors to avoid extra indirection.
    const double* __restrict A_data = nullptr;
    const double* __restrict B_data = nullptr;
    double* __restrict C_data = nullptr;

    // Flatten the 2‑D vectors into 1‑D arrays.
    std::vector<double> A_flat(m * m);
    std::vector<double> B_flat(m * n);
    std::vector<double> C_flat(m * n);

    // Copy the data into contiguous buffers.
    for (int i = 0; i < m; ++i)
        for (int j = 0; j < m; ++j)
            A_flat[i * m + j] = A[i][j];

    for (int i = 0; i < m; ++i)
        for (int j = 0; j < n; ++j)
            B_flat[i * n + j] = B[i][j];

    for (int i = 0; i < m; ++i)
        for (int j = 0; j < n; ++j)
            C_flat[i * n + j] = C[i][j];

    // Use a more cache‑friendly order: outermost loop over rows (i),
    // then columns (j).  Parallelise the two loops with OpenMP.
    #pragma omp parallel for schedule(static) collapse(2)
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            double temp2 = 0.0;
            const double Bij = B_flat[i * n + j];

            // Compute the low‑triangular contribution.
            for (int k = 0; k < i; ++k) {
                double aik = A_flat[i * m + k];
                C_flat[k * n + j] += alpha * Bij * aik;
                temp2 += B_flat[k * n + j] * aik;
            }

            // Finish the current element.
            C_flat[i * n + j] = beta * C_flat[i * n + j] +
                                alpha * Bij * A_flat[i * m + i] + alpha * temp2;
        }
    }

    // Copy results back into the original 2‑D vectors.
    for (int i = 0; i < m; ++i)
        for (int j = 0; j < n; ++j)
            C[i][j] = C_flat[i * n + j];
}
