/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_2mm(int ni, int nj, int nk, int nl,
                double alpha,
                double beta,
                std::vector<std::vector<double>>& tmp,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D)
{
    /* Block sizes chosen to fit on typical L1/L2 caches (tuned empirically) */
    constexpr int B1 = 64;   // outer block for i
    constexpr int B2 = 64;   // outer block for j
    constexpr int BK = 64;   // block for k

    /* 1. Compute tmp = alpha * A * B   (ni × nj result) */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int ii = 0; ii < ni; ii += B1) {
        for (int jj = 0; jj < nj; jj += B2) {
            int i_end = std::min(ii + B1, ni);
            int j_end = std::min(jj + B2, nj);
            for (int i = ii; i < i_end; ++i) {
                for (int j = jj; j < j_end; ++j) {
                    double sum = 0.0;
                    for (int kk = 0; kk < nk; kk += BK) {
                        int k_end = std::min(kk + BK, nk);
                        for (int k = kk; k < k_end; ++k) {
                            sum += alpha * A[i][k] * B[k][j];
                        }
                    }
                    tmp[i][j] = sum;
                }
            }
        }
    }

    /* 2. Compute D = beta * D + tmp * C   (ni × nl result) */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int ii = 0; ii < ni; ii += B1) {
        for (int jj = 0; jj < nl; jj += B2) {
            int i_end = std::min(ii + B1, ni);
            int j_end = std::min(jj + B2, nl);
            for (int i = ii; i < i_end; ++i) {
                /* scale D[i][j] by beta once per i–j pair */
                for (int j = jj; j < j_end; ++j) {
                    double acc = beta * D[i][j];
                    for (int kk = 0; kk < nj; kk += BK) {
                        int k_end = std::min(kk + BK, nj);
                        for (int k = kk; k < k_end; ++k) {
                            acc += tmp[i][k] * C[k][j];
                        }
                    }
                    D[i][j] = acc;
                }
            }
        }
    }
}
