/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {

    /* 1. Zero y in parallel */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j)
        y[j] = 0.0;

    /* 2. Each thread keeps a private copy of the output vector
       to avoid atomic operations. */
    int nthreads = omp_get_max_threads();
    std::vector<std::vector<double>> y_local(nthreads, std::vector<double>(n, 0.0));

    /* 3. Main computation */
    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        double* const * A_rows = reinterpret_cast<double* const *>(&A[0]);   // row pointers

        #pragma omp for schedule(static)
        for (int i = 0; i < m; ++i) {
            /* local temporary */
            double dot = 0.0;
            double* Ai = &A_rows[i][0];

            /* compute tmp[i] = dot(A[i], x) */
            for (int j = 0; j < n; ++j)
                dot += Ai[j] * x[j];
            tmp[i] = dot;

            /* accumulate into the private y copy */
            for (int j = 0; j < n; ++j)
                y_local[tid][j] += Ai[j] * dot;
        }
    }

    /* 4. Reduction of local y copies into the final y */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j) {
        double sum = 0.0;
        for (int t = 0; t < nthreads; ++t)
            sum += y_local[t][j];
        y[j] = sum;
    }
}
