#include <vector>
#include <cmath>
#include <omp.h>

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev) {
    const double eps = 0.1;
    const double inv_sqrt_n = 1.0 / std::sqrt(static_cast<double>(n));

    /* ---- compute means --------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) sum += data[i][j];
        mean[j] = sum / n;
    }

    /* ---- compute standard deviations ------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sumsq = 0.0;
        double mu = mean[j];
        for (int i = 0; i < n; ++i) {
            double dif = data[i][j] - mu;
            sumsq += dif * dif;
        }
        stddev[j] = std::sqrt(sumsq / n);
        if (stddev[j] <= eps) stddev[j] = 1.0;
    }

    /* ---- normalize data -------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            data[i][j] = (data[i][j] - mean[j]) * inv_sqrt_n / stddev[j];
        }
    }

    /* ---- compute correlation matrix ------------------------------------- */
    // diagonal entries
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) corr[i][i] = 1.0;

    // off–diagonal entries
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < m - 1; ++i) {
        for (int j = i + 1; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) sum += data[k][i] * data[k][j];
            corr[i][j] = sum;
            corr[j][i] = sum;
        }
    }
}
