#include <cmath>
#include <vector>
#include <omp.h>

/* Main computational kernel.  The algorithm is a standard
   Cholesky factorisation of a symmetric positive‑definite
   matrix.  Because each row depends on all previous rows,
   the outermost loop cannot be parallelised safely, but
   the inner work is expressed in a flat, cache‑friendly
   manner to maximise throughput. */
void kernel_cholesky(int n,
                     std::vector<std::vector<double>>& A)
{
    /* Flatten the input 2‑D structure into a single pointer
       to avoid the indirection of A[i][j] and to keep the
       accesses contiguous.  The row major order matches the
       layout used by the caller, so the behaviour is unchanged. */
    double* base = &A[0][0];

    for (int i = 0; i < n; ++i) {
        /* Process the sub‑diagonal elements A[i][j] (j < i) */
        for (int j = 0; j < i; ++j) {
            double sum = -base[i * n + j];
            // Unroll the inner k loop in chunks of 4
            int k = 0;
            for (; k + 3 < j; k += 4) {
                sum -= base[i * n + k]   * base[j * n + k];
                sum -= base[i * n + k+1] * base[j * n + k+1];
                sum -= base[i * n + k+2] * base[j * n + k+2];
                sum -= base[i * n + k+3] * base[j * n + k+3];
            }
            for (; k < j; ++k) {
                sum -= base[i * n + k] * base[j * n + k];
            }
            base[i * n + j] = sum / base[j * n + j];
        }

        /* Process the diagonal element A[i][i] */
        double sum = base[i * n + i];
        int k = 0;
        for (; k + 3 < i; k += 4) {
            double v0 = base[i * n + k];
            double v1 = base[i * n + k+1];
            double v2 = base[i * n + k+2];
            double v3 = base[i * n + k+3];
            sum -= v0 * v0 + v1 * v1 + v2 * v2 + v3 * v3;
        }
        for (; k < i; ++k) {
            double v = base[i * n + k];
            sum -= v * v;
        }
        base[i * n + i] = std::sqrt(sum);
    }
}
