/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y) {

    // Allocate a temporary buffer on the stack if small, otherwise on the heap
    double* z = nullptr;
    if (n <= 1024) {
        // 8 KiB is normally on the stack
        double stack_z[1024] = {0.0};
        z = stack_z;
    } else {
        z = static_cast<double*>(std::malloc(sizeof(double)*static_cast<std::size_t>(n)));
    }

    double* R = r.data();
    double* Y = y.data();

    Y[0] = -R[0];
    double beta = 1.0;
    double alpha = -R[0];

    for (int k = 1; k < n; ++k) {
        beta = (1.0 - alpha * alpha) * beta;
        double sum = 0.0;

        // Compute the correlation sum
        const double* r_ptr = R + k - 1;        // points to r[k-1]
        const double* y_ptr = Y;                // points to y[0]
        const double* y_rev = Y + k - 1;        // points to y[k-1]
        for (int i = 0; i < k; ++i) {
            sum += *r_ptr-- * *y_ptr++;
        }

        alpha = -(R[k] + sum) / beta;

        // Compute new y values into z[]
        const double* y_rev_tmp = Y + k - 1;    // points to y[k-1]
        for (int i = 0; i < k; ++i) {
            z[i] = Y[i] + alpha * y_rev_tmp[i];
        }

        // Copy back from z to y
        for (int i = 0; i < k; ++i) {
            Y[i] = z[i];
        }

        Y[k] = alpha;
    }

    if (z != nullptr && z != reinterpret_cast<double(*)[1024]>(z)) {
        std::free(z);
    }
}
