#include <vector>
#include <cstddef>
#include <omp.h>

/* The function signature must stay exactly the same.
   Internally we flatten the vectors into 1‑D arrays
   so that all accesses are contiguous and cache friendly. */
void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    /* Flatten the 2‑D std::vector layout into 1‑D
       (row major) pointers for fast access. */
    const std::size_t a_stride = nk;
    const std::size_t b_stride = nj;
    const std::size_t c_stride = nj;

    /* Pointers to the start of each row of A, B, C.
       We cache the addresses for each row once per outer loop. */
    std::vector<const double*> A_rows(ni);
    std::vector<const double*> B_rows(nk);
    std::vector<double*> C_rows(ni);
    for (int i = 0; i < ni; ++i) A_rows[i]  = A[i].data();
    for (int k = 0; k < nk; ++k) B_rows[k]  = B[k].data();
    for (int i = 0; i < ni; ++i) C_rows[i]  = C[i].data();

    /* Parallelize over the outermost dimension (rows of C).
       The work for each row is independent. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i)
    {
        double* c_row = C_rows[i];
        const double* a_row = A_rows[i];

        /* Scale the i‑th row of C by beta */
        for (int j = 0; j < nj; ++j)
            c_row[j] *= beta;

        /* Update the i‑th row of C:  C[i,:] += alpha * A[i,:] * B */
        for (int k = 0; k < nk; ++k)
        {
            double aik = alpha * a_row[k];
            const double* b_row = B_rows[k];

            /* Unroll inner loop (pitch 4) for higher IPC */
            int j = 0;
            for (; j <= nj - 4; j += 4)
            {
                c_row[j]     += aik * b_row[j];
                c_row[j + 1] += aik * b_row[j + 1];
                c_row[j + 2] += aik * b_row[j + 2];
                c_row[j + 3] += aik * b_row[j + 3];
            }
            /* Handle remaining elements */
            for (; j < nj; ++j)
                c_row[j] += aik * b_row[j];
        }
    }
}
```

**Key optimizations**

1. **Contiguous memory access** – Access the underlying data of the
   `std::vector<std::vector<double>>` directly via pointers.
2. **Cache‑friendly loop order** – The outermost loop is over `i`
   (row of C), which is done independently in each thread.
3. **OpenMP parallelism** – Work is split across 8 threads automatically.
4. **Vectorization help** – Small manual loop unrolling (by 4) encourages
   the compiler to use SIMD instructions.
5. **No semantic change** – The algorithm and results are identical to the
   original implementation.

