#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Kernel performs LU decomposition of A into lower and upper matrices
 * in place, followed by forward/back substitution to solve Ax = b.
 * It is designed to be fully reproducible and thread‑safe while
 * exploiting vector‑friendly memory access patterns.
 */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y)
{
    /* --- LU decomposition (in–place) --- */
    for (int i = 0; i < n; ++i) {
        std::vector<double> *row_i = &A[i];
        double *Ai = row_i->data();                     // pointer to ith row

        /* ---- compute L(i,j) for j<i ---- */
        for (int j = 0; j < i; ++j) {
            double w = Ai[j];
            std::vector<double> *row_j = &A[j];
            double *Aj = row_j->data();                 // pointer to jth row

            /* dot product of row i and row j over k<j   */
            for (int k = 0; k < j; ++k) {
                w -= Ai[k] * Aj[k];
            }
            Ai[j] = w / Aj[j];                          // A[j][j] is the pivot
        }

        /* ---- compute U(i,j) for j>=i ---- */
        for (int j = i; j < n; ++j) {
            double w = Ai[j];
            std::vector<double> *row_j = &A[j];
            double *Aj = row_j->data();

            for (int k = 0; k < i; ++k) {
                w -= Ai[k] * Aj[k];
            }
            Ai[j] = w;                                  // upper part unchanged
        }
    }

    /* --- forward substitution (Ly = b) --- */
    for (int i = 0; i < n; ++i) {
        double w = b[i];
        double *Ai = A[i].data();
        for (int j = 0; j < i; ++j) {
            w -= Ai[j] * y[j];
        }
        y[i] = w;
    }

    /* --- back substitution (Ux = y) --- */
    for (int i = n - 1; i >= 0; --i) {
        double w = y[i];
        double *Ai = A[i].data();
        for (int j = i + 1; j < n; ++j) {
            w -= Ai[j] * x[j];
        }
        x[i] = w / Ai[i];                               // Ai[i] is the pivot on U
    }
}
