                    double* Aip = A[i+1][j].data();
                    double* Aim = A[i-1][j].data();
                    double* Ajp = A[i][j+1].data();
                    double* Ajm = A[i][j-1].data();
                    double* Akp = A[i][j].data() + 1;  // will shift inside loop
                    double* Akm = Ai - 1;
