#include <vector>
#include <omp.h>

/* Main computational kernel.  The whole function will be timed,
   including the call and return. */
void kernel_jacobi_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A,
                      std::vector<std::vector<double>>& B)
{
    /* 2D array is described as a vector of rows.  Each row is a
       std::vector<double> allocated separately.  We therefore
       access the data row‑by‑row in the inner loops, which keeps
       the compiler from inserting expensive index checks.  The code
       is fully parallelised on the outermost loop with OpenMP, using
       static scheduling so that each thread gets a roughly equal
       number of rows. */

    const double coeff = 0.2;          // factor used in the stencil
    const int Nminus1 = n - 1;         // we never touch the boundaries

#pragma omp parallel
    {
        /* each thread gets a strip of rows */
#pragma omp for schedule(static)
        for (int t = 0; t < tsteps; ++t)
        {
            /* ---------- first sweep : A → B ---------- */
            for (int i = 1; i < Nminus1; ++i)
            {
                double* a_row  = A[i].data();
                double* a_up   = A[i-1].data();
                double* a_down = A[i+1].data();
                double* b_row  = B[i].data();

                /* the first column (j=0) and last column (j=n-1)
                   are not touched, we start at j=1 and end at j=n-2 */
                for (int j = 1; j < Nminus1; ++j)
                {
                    const double a00 = a_row[j];
                    const double aL  = a_row[j-1];
                    const double aR  = a_row[j+1];
                    const double aU  = a_up[j];
                    const double aD  = a_down[j];

                    b_row[j] = coeff * (a00 + aL + aR + aU + aD);
                }
            }

            /* ---------- second sweep : B → A ---------- */
            for (int i = 1; i < Nminus1; ++i)
            {
                double* b_row  = B[i].data();
                double* b_up   = B[i-1].data();
                double* b_down = B[i+1].data();
                double* a_row  = A[i].data();

                for (int j = 1; j < Nminus1; ++j)
                {
                    const double b00 = b_row[j];
                    const double bL  = b_row[j-1];
                    const double bR  = b_row[j+1];
                    const double bU  = b_up[j];
                    const double bD  = b_down[j];

                    a_row[j] = coeff * (b00 + bL + bR + bU + bD);
                }
            }
        }
    }
}
