#include <vector>
#include <omp.h>

/* Flattened 2D grid access */
struct Grid {
    const int n;            // size (n x n)
    const int sz;           // n * n
    double *data;           // contiguous storage

    Grid(int n_) : n(n_), sz(n_*n_), data(new double[sz]) {}
    ~Grid() { delete[] data; }

    inline double &operator()(int i, int j) {
        return data[i * n + j];
    }
    inline const double &operator()(int i, int j) const {
        return data[i * n + j];
    }
};

void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q) {
    /* ``Flatten`` the 2‑D vectors – the original layout is
       row major, so a single contiguous array preserves that. */
    Grid fu(n), fv(n), fp(n), fq(n);
    for (int i=0;i<n;i++)
        for (int j=0;j<n;j++) {
            fu(i,j)=u[i][j];  fv(i,j)=v[i][j];
            fp(i,j)=p[i][j];  fq(i,j)=q[i][j];
        }

    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1 = 2.0, B2 = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);
    const double a = -mul1/2.0, b = 1.0 + mul1,  c = a;
    const double d = -mul2/2.0, e = 1.0 + mul2,  f = d;

    /* OpenMP: the outer time loop is serial, but the two inner
       spatial sweeps are embarrassingly parallel. */
    for (int t=1; t<=tsteps; ++t) {
        /* first sweep – compute v[*][*] */
        #pragma omp parallel for schedule(static)
        for (int i=1; i<n-1; ++i) {
            fv(0,i)  = 1.0;
            fp(i,0)  = 0.0;
            fq(i,0)  = fv(0,i);

            for (int j=1; j<n-1; ++j) {
                double denom = a * fp(i,j-1) + b;
                fp(i,j) = -c / denom;
                fq(i,j) = (-d * fu(j,i-1) + (1.0+2.0*d)*fu(j,i)
                           - f * fu(j,i+1) - a * fq(i,j-1)) / denom;
            }

            fv(n-1,i) = 1.0;
            for (int j=n-2; j>=1; --j) {
                fv(j,i) = fp(i,j) * fv(j+1,i) + fq(i,j);
            }
        }

        /* second sweep – compute u[*][*] */
        #pragma omp parallel for schedule(static)
        for (int i=1; i<n-1; ++i) {
            fu(i,0)  = 1.0;
            fp(i,0)  = 0.0;
            fq(i,0)  = fu(i,0);

            for (int j=1; j<n-1; ++j) {
                double denom = d * fp(i,j-1) + e;
                fp(i,j) = -f / denom;
                fq(i,j) = (-a * fv(i-1,j) + (1.0+2.0*a)*fv(i,j)
                           - c * fv(i+1,j) - d * fq(i,j-1)) / denom;
            }

            fu(i,n-1) = 1.0;
            for (int j=n-2; j>=1; --j) {
                fu(i,j) = fp(i,j) * fu(i,j+1) + fq(i,j);
            }
        }
    }

    /* Copy back to the input vectors */
    for (int i=0;i<n;i++)
        for (int j=0;j<n;j++) {
            u[i][j]=fu(i,j);
            v[i][j]=fv(i,j);
            p[i][j]=fp(i,j);
            q[i][j]=fq(i,j);
        }
}
