#include <vector>
#include <cstddef>
#include <cmath>
#include <omp.h>

/* Helper to flatten 2D std::vector::vector into a contiguous block
   and keep original 2D interfaces.                     */
namespace detail {
    template<typename T>
    struct Flat2D {
        std::vector<T> data;
        std::size_t nx, ny;

        inline T& operator()(std::size_t i, std::size_t j) {
            return data[i * ny + j];
        }
        inline const T& operator()(std::size_t i, std::size_t j) const {
            return data[i * ny + j];
        }
    };

    /* Convert std::vector<std::vector<T>> to Flat2D by copying data.
       After conversion the caller can replace its 2D vector with the
       contiguous representation.                                     */
    template<typename T>
    Flat2D<T> flatten(const std::vector<std::vector<T>>& v) {
        Flat2D<T> f{v[0].size() * v.size(), v.size(), v[0].size()};
        for (std::size_t i = 0; i < v.size(); ++i)
            for (std::size_t j = 0; j < v[0].size(); ++j)
                f.data[i * f.ny + j] = v[i][j];
        return f;
    }

    /* Copy back the contiguous data to the original 2D vector.      */
    template<typename T>
    void copy_back(const Flat2D<T>& f, std::vector<std::vector<T>>& v) {
        for (std::size_t i = 0; i < f.nx; ++i)
            for (std::size_t j = 0; j < f.ny; ++j)
                v[i][j] = f(i, j);
    }
}

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_fdtd_2d(int tmax,
                    int nx,
                    int ny,
                    std::vector<std::vector<double>>& ex,
                    std::vector<std::vector<double>>& ey,
                    std::vector<std::vector<double>>& hz,
                    std::vector<double>& _fict_) {
    /* Flatten the 2‑D arrays for cache efficiency. */
    auto fex = detail::flatten(ex);
    auto fey = detail::flatten(ey);
    auto fhz = detail::flatten(hz);

    /* Update loop: everything is pre‑sliced into contiguous buffers. */
    for (int t = 0; t < tmax; ++t) {
        /* ---------------------------------------------------------------- */
        /* 1. Update ey[0][j] = _fict_[t]  (j:0..ny-1)                       */
        /*    Parallelized across j.                                          */
        #pragma omp parallel for schedule(static)
        for (int j = 0; j < ny; ++j)
            fey(0, j) = _fict_[t];

        /* ---------------------------------------------------------------- */
        /* 2. Update ey[i][j] (i:1..nx-1, j:0..ny-1)                         */
        /*    Parallelize over i (outer) to keep inner loop contiguous.      */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < nx; ++i) {
            double* ey_ptr   = &fey(i, 0);
            const double* hz_ptr  = &fhz(i, 0);
            const double* hz_np1 = &fhz(i - 1, 0);
            for (int j = 0; j < ny; ++j)
                ey_ptr[j] -= 0.5 * (hz_ptr[j] - hz_np1[j]);
        }

        /* ---------------------------------------------------------------- */
        /* 3. Update ex[i][j] (i:0..nx-1, j:1..ny-1)                         */
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < nx; ++i) {
            double* ex_ptr   = &fex(i, 0);
            const double* hz_ptr = &fhz(i, 0);
            const double* hz_nj1  = &fhz(i, 1);
            for (int j = 1; j < ny; ++j)
                ex_ptr[j] -= 0.5 * (hz_nj1[j-1] - hz_ptr[j-1]);
        }

        /* ---------------------------------------------------------------- */
        /* 4. Update hz[i][j] (i:0..nx-2, j:0..ny-2)                         */
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 0; i < nx - 1; ++i) {
            for (int j = 0; j < ny - 1; ++j) {
                fhz(i, j) -= 0.7 *
                    ( fex(i, j + 1) - fex(i, j)
                    + fey(i + 1, j) - fey(i, j) );
            }
        }
    }

    /* Copy back the results to the original std::vector containers. */
    detail::copy_back(fex, ex);
    detail::copy_back(fey, ey);
    detail::copy_back(fhz, hz);
}
