#include <vector>

/* Seidel smoothing kernel – in‑place stencil update.
   The algorithm is deliberately left single‑threaded because the
   original implementation performs a left‑to‑right scan that
   depends on the updated values of the current row.  Parallelising
   the row loop would change the exact evaluation order and is
   therefore forbidden.  The optimisation focus is on cache friendliness
   and inner‑loop unrolling.                                                              */
void kernel_seidel_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A) {
    const double inv9 = 1.0 / 9.0;

    for (int t = 0; t < tsteps; ++t) {
        for (int i = 1; i <= n - 2; ++i) {
            const double* prev = A[i - 1].data();
            double*       cur  = A[i].data();
            const double* next = A[i + 1].data();

            /* Main inner loop – unrolled by 4 for better performance.
               The range is divided into a remainder part and the
               bulk that is processed in chunks of four elements.      */
            int j = 1;
            // Handle the remainder before the bulk
            for (; j <= n - 3; j += 4) {
                // Load values for j, j+1, j+2, j+3
                const double p0  = prev[j - 1],   p1  = prev[j],   p2  = prev[j + 1];
                const double p0p = prev[j + 2],   p1p = prev[j + 3], p2p = prev[j + 4];
                const double c0  = cur[j - 1],    c1  = cur[j],    c2  = cur[j + 1];
                const double c0p = cur[j + 2],    c1p = cur[j + 3], c2p = cur[j + 4];
                const double n0  = next[j - 1],   n1  = next[j],   n2  = next[j + 1];
                const double n0p = next[j + 2],   n1p = next[j + 3], n2p = next[j + 4];

                cur[j]   = (p0 + p1 + p2 + c0 + c1 + c2 + n0 + n1 + n2)   * inv9;
                cur[j+1] = (p1 + p2 + p0p + c1 + c2 + c0p + n1 + n2 + n0p) * inv9;
                cur[j+2] = (p2 + p0p + p1p + c2 + c0p + c1p + n2 + n0p + n1p) * inv9;
                cur[j+3] = (p0p + p1p + p2p + c0p + c1p + c2p + n0p + n1p + n2p) * inv9;
            }

            // Process any remaining elements (at most 3)
            for (; j <= n - 2; ++j) {
                cur[j] = (prev[j - 1] + prev[j] + prev[j + 1] +
                          cur[j - 1] + cur[j] + cur[j + 1] +
                          next[j - 1] + next[j] + next[j + 1]) * inv9;
            }
        }
    }
}
