/*  Optimised Deriche filter kernel
 *  Maintains exact behaviour but rewrites the implementation to use
 *  contiguous memory access, reduces expensive function calls, and
 *  parallelises the outer loops with OpenMP.
 */

#include <cmath>
#include <vector>
#include <cstddef>

void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* Pre‑compute constants once */
    const float exp_alpha  = std::exp(-alpha);
    const float exp_2alpha = exp_alpha * exp_alpha;
    const float denom      = 1.0f + 2.0f * static_cast<float>(alpha) * exp_alpha
                             - exp_2alpha;
    const float k          = 1.0f - exp_alpha * (1.0f - exp_alpha) / denom;

    const float a1 = k,     a5 = k;
    const float a2 = k * exp_alpha * (static_cast<float>(alpha) - 1.0f);
    const float a6 = a2;
    const float a3 = k * exp_alpha * (static_cast<float>(alpha) + 1.0f);
    const float a7 = a3;
    const float a4 = -k * exp_2alpha, a8 = a4;
    const float b1 = std::pow(2.0f, -static_cast<float>(alpha));
    const float b2 = -exp_2alpha;
    const float c1 = 1.0f, c2 = 1.0f;

    const std::ptrdiff_t stride = h;
    const float*  in  = &imgIn[0][0];
    float*        out = &imgOut[0][0];
    float*        y1p = &y1[0][0];
    float*        y2p = &y2[0][0];

    /* 1. Forward horizontal pass (y1) */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        const std::ptrdiff_t base = static_cast<std::ptrdiff_t>(i) * stride;
        for (int j = 0; j < h; ++j) {
            float val = in[base + j];
            y1p[base + j] = a1 * val + a2 * xm1 + b1 * ym1 + b2 * ym2;
            xm1 = val;
            ym2 = ym1;
            ym1 = y1p[base + j];
        }
    }

    /* 2. Backward horizontal pass (y2) */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        const std::ptrdiff_t base = static_cast<std::ptrdiff_t>(i) * stride;
        for (int j = h - 1; j >= 0; --j) {
            float val = in[base + j];
            y2p[base + j] = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            xp2 = xp1;
            xp1 = val;
            yp2 = yp1;
            yp1 = y2p[base + j];
        }
    }

    /* 3. Combine horizontal results to imgOut */
#pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i) {
        const std::ptrdiff_t base = static_cast<std::ptrdiff_t>(i) * stride;
        for (int j = 0; j < h; ++j) {
            out[base + j] = c1 * (y1p[base + j] + y2p[base + j]);
        }
    }

    /* 4. Forward vertical pass (y1) */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float ym1 = 0.0f, ym2 = 0.0f, tm1 = 0.0f;
        for (int i = 0; i < w; ++i) {
            float val = out[static_cast<std::ptrdiff_t>(i) * stride + j];
            y1p[static_cast<std::ptrdiff_t>(i) * stride + j]
                = a5 * val + a6 * tm1 + b1 * ym1 + b2 * ym2;
            tm1 = val;
            ym2 = ym1;
            ym1 = y1p[static_cast<std::ptrdiff_t>(i) * stride + j];
        }
    }

    /* 5. Backward vertical pass (y2) */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float yp1 = 0.0f, yp2 = 0.0f, tp1 = 0.0f, tp2 = 0.0f;
        for (int i = w - 1; i >= 0; --i) {
            float val = out[static_cast<std::ptrdiff_t>(i) * stride + j];
            y2p[static_cast<std::ptrdiff_t>(i) * stride + j]
                = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            tp2 = tp1;
            tp1 = val;
            yp2 = yp1;
            yp1 = y2p[static_cast<std::ptrdiff_t>(i) * stride + j];
        }
    }

    /* 6. Final combination */
#pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i) {
        const std::ptrdiff_t base = static_cast<std::ptrdiff_t>(i) * stride;
        for (int j = 0; j < h; ++j) {
            out[base + j] = c2 * (y1p[base + j] + y2p[base + j]);
        }
    }
}
